from pathlib import Path

BASE = Path(r"C:\Users\MSI\Desktop\kik_proje")
PY = BASE / ".py"
PKG = PY / "199"

def write(name, text):
    p = PKG / name
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(text, encoding="utf-8")

CONFIG = '# -*- coding: utf-8 -*-\nfrom pathlib import Path\nBASE_DIR = Path(r"C:\\Users\\MSI\\Desktop\\kik_proje")\nPY_DIR = BASE_DIR / ".py"\nSTATE_DIR = BASE_DIR / "production_state"\nREPORT_DIR = BASE_DIR / "raporlar"\nREGISTRY_DIR = STATE_DIR / "service_registry"\nJOB_QUEUE_DIR = STATE_DIR / "job_queue"\nSERVICE_REGISTRY_FILE = REGISTRY_DIR / "199_service_registry.json"\nQUEUE_FILE = JOB_QUEUE_DIR / "198_job_queue_state.json"\nWORKER_FILE = JOB_QUEUE_DIR / "198_worker_state.json"\nMIN_DISK_GB = 50\n'

UTILS = '# -*- coding: utf-8 -*-\nimport json, shutil\nfrom pathlib import Path\nfrom datetime import datetime\n\ndef now_stamp():\n    return datetime.now().strftime("%Y%m%d_%H%M%S")\n\ndef now_text():\n    return datetime.now().strftime("%Y-%m-%d %H:%M:%S")\n\ndef ensure_dirs(*dirs):\n    for d in dirs:\n        Path(d).mkdir(parents=True, exist_ok=True)\n\ndef disk_free_gb(path):\n    usage = shutil.disk_usage(str(path))\n    return round(usage.free / (1024 ** 3), 2)\n\ndef safe_read(path, limit_chars=500000):\n    path = Path(path)\n    if not path.exists():\n        return ""\n    for enc in ("utf-8", "utf-8-sig", "cp1254", "latin-1"):\n        try:\n            return path.read_text(encoding=enc, errors="ignore")[:limit_chars]\n        except Exception:\n            pass\n    return ""\n\ndef safe_json(path):\n    path = Path(path)\n    if not path.exists():\n        return None\n    try:\n        return json.loads(safe_read(path))\n    except Exception:\n        return None\n\ndef write_json(path, data):\n    path = Path(path)\n    path.parent.mkdir(parents=True, exist_ok=True)\n    path.write_text(json.dumps(data, ensure_ascii=False, indent=2), encoding="utf-8")\n\ndef latest_file(folder, pattern):\n    folder = Path(folder)\n    if not folder.exists():\n        return None\n    files = list(folder.glob(pattern))\n    if not files:\n        return None\n    files.sort(key=lambda p: p.stat().st_mtime, reverse=True)\n    return files[0]\n\ndef find_scripts(py_dir, prefix, must_contain=None):\n    must_contain = must_contain or []\n    py_dir = Path(py_dir)\n    candidates = []\n    candidates.extend(py_dir.glob(f"{prefix}*.py"))\n    candidates.extend(py_dir.glob(f"*{prefix}*.py"))\n    candidates = list(set(candidates))\n    if must_contain:\n        candidates = [p for p in candidates if all(t.lower() in p.name.lower() for t in must_contain)]\n    candidates.sort(key=lambda p: p.stat().st_mtime, reverse=True)\n    return candidates\n\ndef file_info(path):\n    path = Path(path)\n    return {\n        "path": str(path),\n        "name": path.name,\n        "size_kb": round(path.stat().st_size / 1024, 2),\n        "modified_at": datetime.fromtimestamp(path.stat().st_mtime).strftime("%Y-%m-%d %H:%M:%S"),\n    }\n'

REGISTRY = '# -*- coding: utf-8 -*-\nfrom config import PY_DIR, STATE_DIR, REPORT_DIR, REGISTRY_DIR, SERVICE_REGISTRY_FILE\nfrom utils import now_stamp, ensure_dirs, disk_free_gb, find_scripts, file_info, write_json\n\nSERVICES = {\n    "core": {"181":"Production Controller","192":"Resume Engine","193":"Smart Resume Validation","194":"Production Guardian","195":"Runtime Monitor"},\n    "certification": {"196":"Production Certification Suite","196B":"Dynamic Certification"},\n    "recovery": {"197":"Recovery Manager"},\n    "orchestration": {"198":"Queue / Worker / Controlled Execution","199":"Production Manager"},\n    "pipeline": {"168":"Production","188":"Auto Cleaner","172":"AI Quality","175":"Coverage","176":"Priority","177":"Legal Accuracy","185":"Self Healing","178":"Merge","179":"Optimize","180":"Complexity","169":"DB Import","170":"Export","173":"Acceptance","182":"Drift","183":"Sampling","184":"Dashboard","190":"Supervisor"}\n}\n\ndef run():\n    ensure_dirs(STATE_DIR, REPORT_DIR, REGISTRY_DIR)\n    ts = now_stamp()\n    registry = {"module":"199 Package Service Registry","disk_free_gb":disk_free_gb(PY_DIR.parent),"categories":{},"flat_services":{}}\n    for cat, services in SERVICES.items():\n        registry["categories"][cat] = {}\n        for prefix, label in services.items():\n            scripts = find_scripts(PY_DIR, prefix)\n            primary = scripts[0] if scripts else None\n            item = {"prefix":prefix,"label":label,"category":cat,"status":"FOUND" if primary else "MISSING","primary_script":file_info(primary) if primary else None,"script_count":len(scripts)}\n            registry["categories"][cat][prefix] = item\n            registry["flat_services"][prefix] = item\n    found = sum(1 for x in registry["flat_services"].values() if x["status"]=="FOUND")\n    total = len(registry["flat_services"])\n    score = 100 if found == total else max(0, 100 - (total-found)*5)\n    decision = "REGISTRY READY" if found == total else "REGISTRY REVIEW"\n    result = {"score":score,"decision":decision,"errors":[],"warnings":[]}\n    state = STATE_DIR / f"199_pkg_registry_state_{ts}.json"\n    report = REPORT_DIR / f"199_pkg_registry_raporu_{ts}.txt"\n    write_json(SERVICE_REGISTRY_FILE, registry)\n    write_json(state, {"registry":registry,"result":result})\n    report.write_text("\\n".join(["="*80,"199 PACKAGE - SERVICE REGISTRY","="*80,f"Score    : {score} / 100",f"Decision : {decision}",f"Found    : {found} / {total}","", "Dosyalar:",str(SERVICE_REGISTRY_FILE),str(state),str(report)]), encoding="utf-8")\n    return {"registry":registry,"result":result,"paths":{"registry":str(SERVICE_REGISTRY_FILE),"state":str(state),"report":str(report)}}\n'

HEALTH = '# -*- coding: utf-8 -*-\nimport sqlite3\nfrom config import BASE_DIR, STATE_DIR, REPORT_DIR, SERVICE_REGISTRY_FILE, QUEUE_FILE, WORKER_FILE, MIN_DISK_GB\nfrom utils import now_stamp, ensure_dirs, disk_free_gb, safe_json, latest_file, safe_read, write_json\n\ndef discover_db():\n    candidates = [p for p in BASE_DIR.rglob("*.db") if "kik" in p.name.lower()]\n    candidates = list(set(candidates))\n    candidates.sort(key=lambda p: p.stat().st_mtime, reverse=True)\n    if not candidates:\n        return {"status":"FAIL","count":0,"message":"DB yok"}\n    db = candidates[0]\n    try:\n        conn = sqlite3.connect(str(db)); cur = conn.cursor()\n        tables = [x[0] for x in cur.execute("SELECT name FROM sqlite_master WHERE type=\'table\'").fetchall()]\n        table = "hukuki_kartlar" if "hukuki_kartlar" in tables else (tables[0] if tables else None)\n        if not table:\n            return {"status":"FAIL","path":str(db),"count":0,"message":"Tablo yok"}\n        count = cur.execute(f"SELECT COUNT(*) FROM {table}").fetchone()[0]\n        conn.close()\n        return {"status":"PASS","path":str(db),"table":table,"count":count,"message":f"DB OK: {count}"}\n    except Exception as e:\n        return {"status":"FAIL","path":str(db),"count":0,"message":str(e)}\n\ndef registry_health():\n    reg = safe_json(SERVICE_REGISTRY_FILE)\n    if not reg:\n        return {"status":"FAIL","found":0,"total":0,"message":"Registry yok"}\n    flat = reg.get("flat_services",{})\n    total = len(flat); found = sum(1 for x in flat.values() if x.get("status")=="FOUND")\n    return {"status":"PASS" if found==total and total else "WARNING","found":found,"total":total,"message":f"{found}/{total} servis"}\n\ndef queue_health():\n    q = safe_json(QUEUE_FILE)\n    if not q:\n        return {"status":"WARNING","total":0,"message":"Queue yok"}\n    jobs = q.get("jobs",[])\n    counts = {}\n    for j in jobs:\n        counts[j.get("status","UNKNOWN")] = counts.get(j.get("status","UNKNOWN"),0)+1\n    return {"status":"PASS","total":len(jobs),"waiting":counts.get("WAITING",0),"running":counts.get("RUNNING",0),"finished":counts.get("FINISHED",0),"failed":counts.get("FAILED",0),"message":f"Queue total={len(jobs)}"}\n\ndef worker_health():\n    w = safe_json(WORKER_FILE)\n    if not w:\n        return {"status":"WARNING","total":0,"message":"Worker yok"}\n    workers = w.get("workers",[])\n    counts = {}\n    for x in workers:\n        counts[x.get("status","UNKNOWN")] = counts.get(x.get("status","UNKNOWN"),0)+1\n    return {"status":"PASS","total":len(workers),"idle":counts.get("IDLE",0),"running":counts.get("RUNNING",0),"message":f"Workers total={len(workers)}"}\n\ndef latest_health(pattern, tokens, label):\n    f = latest_file(STATE_DIR, pattern)\n    if not f:\n        return {"status":"WARNING","message":f"{label} yok"}\n    txt = safe_read(f).lower()\n    ok = any(t.lower() in txt for t in tokens)\n    return {"status":"PASS" if ok else "WARNING","file":str(f),"message":label}\n\ndef run():\n    ensure_dirs(STATE_DIR, REPORT_DIR)\n    ts = now_stamp()\n    free = disk_free_gb(BASE_DIR)\n    parts = {\n        "registry":registry_health(),\n        "db":discover_db(),\n        "disk":{"status":"PASS" if free>=MIN_DISK_GB else "FAIL","free_gb":free,"message":f"Disk {free} GB"},\n        "queue":queue_health(),\n        "worker":worker_health(),\n        "recovery":latest_health("197_v4_recovery_manager_state_*.json",["recovery clean"],"Recovery"),\n        "orchestrator":latest_health("199_v3_orchestrator_state_*.json",["orchestrator certified"],"Orchestrator")\n    }\n    score = 100\n    errors=[]; warnings=[]\n    for k,v in parts.items():\n        if v.get("status")=="FAIL":\n            score-=20; errors.append(k)\n        elif v.get("status")=="WARNING":\n            score-=5; warnings.append(k)\n    score=max(0,score)\n    decision = "PLATFORM BLOCKED" if errors else ("PLATFORM READY" if score>=90 else "PLATFORM REVIEW")\n    result={"score":score,"decision":decision,"errors":errors,"warnings":warnings}\n    state=STATE_DIR/f"199_pkg_health_state_{ts}.json"\n    report=REPORT_DIR/f"199_pkg_health_raporu_{ts}.txt"\n    write_json(state,{"health":parts,"result":result})\n    report.write_text("\\n".join(["="*80,"199 PACKAGE - PLATFORM HEALTH","="*80,f"Score    : {score} / 100",f"Decision : {decision}",f"Errors   : {len(errors)}",f"Warnings : {len(warnings)}",f"DB Count : {parts[\'db\'].get(\'count\')}",f"Queue    : W={parts[\'queue\'].get(\'waiting\')} R={parts[\'queue\'].get(\'running\')} F={parts[\'queue\'].get(\'finished\')} Fail={parts[\'queue\'].get(\'failed\')}",f"Workers  : idle={parts[\'worker\'].get(\'idle\')} running={parts[\'worker\'].get(\'running\')} total={parts[\'worker\'].get(\'total\')}","", "Dosyalar:",str(state),str(report)]), encoding="utf-8")\n    return {"health":parts,"result":result,"paths":{"state":str(state),"report":str(report)}}\n'

MANAGER = '# -*- coding: utf-8 -*-\nimport argparse\nfrom registry import run as run_registry\nfrom health import run as run_health\n\ndef main():\n    parser = argparse.ArgumentParser()\n    parser.add_argument("--registry", action="store_true")\n    parser.add_argument("--health", action="store_true")\n    parser.add_argument("--all", action="store_true")\n    args = parser.parse_args()\n    if args.all or (not args.registry and not args.health):\n        reg = run_registry()\n        health = run_health()\n        print("="*80)\n        print("199 PACKAGE MANAGER TAMAMLANDI")\n        print("="*80)\n        print(f"Registry : {reg[\'result\'][\'decision\']} ({reg[\'result\'][\'score\']}/100)")\n        print(f"Health   : {health[\'result\'][\'decision\']} ({health[\'result\'][\'score\']}/100)")\n        print("")\n        print("Dosyalar:")\n        print(reg["paths"]["report"])\n        print(health["paths"]["report"])\n        return\n    if args.registry:\n        reg = run_registry()\n        print(f"Registry : {reg[\'result\'][\'decision\']} ({reg[\'result\'][\'score\']}/100)")\n    if args.health:\n        health = run_health()\n        print(f"Health : {health[\'result\'][\'decision\']} ({health[\'result\'][\'score\']}/100)")\n\nif __name__ == "__main__":\n    main()\n'

BRIDGE = '# -*- coding: utf-8 -*-\nimport sys\nfrom pathlib import Path\nPACKAGE_DIR = Path(__file__).resolve().parent / "199"\nsys.path.insert(0, str(PACKAGE_DIR))\nfrom manager import main\nif __name__ == "__main__":\n    main()\n'

